import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Login.css';

function Login({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [settings, setSettings] = useState({ logo: null, background_image: null, site_name: 'LOR CGR' });

  useEffect(() => {
    const loadSettings = async () => {
      try {
        const response = await axios.get('/api/settings/public/');
        if (response.data) {
          setSettings({ logo: response.data.logo || null, background_image: response.data.background_image || null, site_name: response.data.site_name || 'LOR CGR' });
        }
      } catch (err) { console.log('Nao foi possivel carregar configuracoes visuais'); }
    };
    loadSettings();
  }, []);

  const getMediaUrl = (path) => { if (!path) return null; if (path.startsWith('http')) return path; return '/media/' + path; };
  const backgroundStyle = settings.background_image ? { backgroundImage: 'url(' + getMediaUrl(settings.background_image) + ')', backgroundSize: 'cover', backgroundPosition: 'center', backgroundRepeat: 'no-repeat', backgroundAttachment: 'fixed' } : {};

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const response = await axios.post('/api/auth/login/', { username, password });
      if (response.data.user) {
        localStorage.setItem('user', JSON.stringify(response.data.user));
        if (onLogin) { onLogin(response.data.user); }
      }
    } catch (err) { setError(err.response?.data?.error || 'Erro ao fazer login'); }
    finally { setLoading(false); }
  };

  return (
    <div className="login-container" style={backgroundStyle}>
      {settings.background_image && <div className="login-overlay"></div>}
      <div className="login-card">
        {settings.logo ? <img src={getMediaUrl(settings.logo)} alt={settings.site_name} className="login-logo" /> : <div className="login-logo-placeholder"><span>LOR</span><span>CGR</span></div>}
        <h1 className="login-title">{settings.site_name}</h1>
        <p className="login-subtitle">Gestao de Redes</p>
        <form onSubmit={handleSubmit} className="login-form">
          {error && <div className="login-error">{error}</div>}
          <div className="form-group"><label htmlFor="username">Usuario</label><input type="text" id="username" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Digite seu usuario" required autoFocus /></div>
          <div className="form-group"><label htmlFor="password">Senha</label><input type="password" id="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Digite sua senha" required /></div>
          <button type="submit" className="login-button" disabled={loading}>{loading ? 'Entrando...' : 'Entrar'}</button>
        </form>
        <div className="login-footer"><p>Sistema de Gestao de Redes</p></div>
      </div>
    </div>
  );
}

export default Login;
