import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import axios from 'axios';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Settings from './components/Settings';
import AuditLogs from './components/AuditLogs';
import Logs from './components/Logs';
import UsersManagement from './components/UsersManagement';
import Inventory from './components/Inventory';
import Terminal from './components/Terminal';
import AIAssistant from './components/AIAssistant';
import Integrations from './components/Integrations';
import Backups from './components/Backups';
import Sidebar from './components/Sidebar';

axios.defaults.withCredentials = true;

function PrivateRoute({ children, user }) {
  if (!user) { return <Navigate to="/login" replace />; }
  return children;
}

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  useEffect(() => {
    const checkAuth = async () => {
      try {
        const response = await axios.get('/api/auth/check/');
        if (response.data.authenticated && response.data.user) {
          setUser(response.data.user);
          localStorage.setItem('user', JSON.stringify(response.data.user));
        } else {
          setUser(null);
          localStorage.removeItem('user');
        }
      } catch (error) {
        setUser(null);
        localStorage.removeItem('user');
      } finally {
        setLoading(false);
      }
    };
    checkAuth();
  }, []);

  const handleLogin = (userData) => {
    setUser(userData);
  };

  const handleLogout = async () => {
    try {
      await axios.post('/api/auth/logout/');
    } catch (error) {
      console.error('Erro no logout:', error);
    }
    setUser(null);
    localStorage.removeItem('user');
    localStorage.clear();
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        height: '100vh',
        background: 'linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%)',
        color: 'white'
      }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{
            width: '50px',
            height: '50px',
            border: '4px solid rgba(255,255,255,0.3)',
            borderTopColor: 'white',
            borderRadius: '50%',
            animation: 'spin 1s linear infinite',
            margin: '0 auto 20px'
          }}></div>
          <p>Carregando...</p>
        </div>
        <style>{'@keyframes spin { to { transform: rotate(360deg); } }'}</style>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        <Route
          path="/login"
          element={user ? <Navigate to="/" replace /> : <Login onLogin={handleLogin} />}
        />
        <Route
          path="/*"
          element={
            <PrivateRoute user={user}>
              <div className="app-container">
                <Sidebar
                  isOpen={sidebarOpen}
                  user={user}
                  onLogout={handleLogout}
                  onToggleSidebar={toggleSidebar}
                />
                <main className="main-content">
                  <Routes>
                    <Route path="/" element={<Dashboard user={user} />} />
                    <Route path="/inventory" element={<Inventory user={user} />} />
                    <Route path="/terminal" element={<Terminal user={user} />} />
                    <Route path="/users" element={<UsersManagement user={user} />} />
                    <Route path="/settings" element={<Settings user={user} />} />
                    <Route path="/logs" element={<Logs user={user} />} />
                    <Route path="/audit-logs" element={<AuditLogs user={user} />} />
                    <Route path="/ai-assistant" element={<AIAssistant user={user} />} />
                    <Route path="/integrations" element={<Integrations user={user} />} />
                    <Route path="/backups" element={<Backups user={user} />} />
                  </Routes>
                </main>
              </div>
            </PrivateRoute>
          }
        />
      </Routes>
    </Router>
  );
}

export default App;
