import React, { useState, useEffect } from 'react';
import { settingsApi } from '../lib/api';
import { Upload, Image, Save, CheckCircle, XCircle, Trash2, Monitor, Wallpaper, Favicon } from 'lucide-react';

const Settings = () => {
  const [activeTab, setActiveTab] = useState('branding');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const [settings, setSettings] = useState({
    system_name: 'LOR CGR',
    logo_url: null,
    login_background_url: null,
    favicon_url: null,
    librenms_enabled: true,
    librenms_url: '',
    librenms_api_token: '',
    phpipam_enabled: true,
    phpipam_url: '',
    phpipam_app_id: '',
    phpipam_app_key: '',
    ai_enabled: true,
    groq_api_key: '',
    groq_model: 'llama-3.3-70b-versatile',
    ai_temperature: 0.7,
    ai_max_tokens: 4096,
    git_enabled: false,
    git_repo_url: '',
  });

  const [uploads, setUploads] = useState({
    logo: null,
    login_background: null,
    favicon: null
  });

  const [previews, setPreviews] = useState({
    logo: null,
    login_background: null,
    favicon: null
  });

  const tabs = [
    { id: 'branding', label: 'Identidade Visual', icon: '🎨' },
    { id: 'apis', label: 'APIs Externas', icon: '🔌' },
    { id: 'ai', label: 'IA (Groq)', icon: '🤖' },
  ];

  useEffect(() => { loadSettings(); }, []);

  const loadSettings = async () => {
    try {
      const res = await settingsApi.get();
      if (res.success && res.data) {
        setSettings(prev => ({ ...prev, ...res.data }));
      }
    } catch (error) {
      console.error('Erro ao carregar:', error);
    }
  };

  const handleFileChange = (type) => (e) => {
    const file = e.target.files[0];
    if (!file) return;
    
    if (file.size > 5 * 1024 * 1024) {
      setMessage({ type: 'error', text: 'Arquivo muito grande. Max: 5MB' });
      return;
    }
    
    if (!file.type.startsWith('image/')) {
      setMessage({ type: 'error', text: 'Selecione uma imagem valida' });
      return;
    }
    
    setUploads(prev => ({ ...prev, [type]: file }));
    setPreviews(prev => ({ ...prev, [type]: URL.createObjectURL(file) }));
  };

  const uploadImage = async (type) => {
    const file = uploads[type];
    if (!file) return;
    
    setLoading(true);
    setMessage({ type: '', text: '' });
    
    try {
      const formData = new FormData();
      formData.append(type, file);
      formData.append('system_name', settings.system_name);
      
      const res = await fetch('/api/settings/settings/logo/', {
        method: 'POST',
        body: formData,
        credentials: 'include'
      });
      
      const data = await res.json();
      
      if (data.success) {
        setSettings(prev => ({ 
          ...prev, 
          logo_url: data.logo_url,
          login_background_url: data.login_background_url,
          favicon_url: data.favicon_url,
          system_name: data.system_name
        }));
        setUploads(prev => ({ ...prev, [type]: null }));
        setMessage({ type: 'success', text: '✅ Imagem salva! Recarregue a pagina para ver.' });
      } else {
        setMessage({ type: 'error', text: '❌ ' + (data.error || 'Erro ao fazer upload') });
      }
    } catch (error) {
      setMessage({ type: 'error', text: '❌ ' + error.message });
    }
    
    setLoading(false);
  };

  const removeImage = async (type) => {
    if (!confirm('Tem certeza que deseja remover esta imagem?')) return;
    
    setLoading(true);
    try {
      const formData = new FormData();
      formData.append('system_name', settings.system_name);
      formData.append('remove_' + type, '1');
      
      const res = await fetch('/api/settings/settings/logo/', {
        method: 'POST',
        body: formData,
        credentials: 'include'
      });
      
      const data = await res.json();
      
      if (data.success) {
        setSettings(prev => ({ ...prev, [type + '_url']: null }));
        setPreviews(prev => ({ ...prev, [type]: null }));
        setMessage({ type: 'success', text: '✅ Imagem removida!' });
      }
    } catch (error) {
      setMessage({ type: 'error', text: '❌ ' + error.message });
    }
    setLoading(false);
  };

  const saveSettings = async () => {
    setLoading(true);
    setMessage({ type: '', text: '' });
    try {
      const res = await settingsApi.save(settings);
      setMessage({ type: res.success ? 'success' : 'error', text: res.success ? '✅ Salvo!' : '❌ ' + res.error });
    } catch (error) {
      setMessage({ type: 'error', text: '❌ ' + error.message });
    }
    setLoading(false);
  };

  const ImageUploader = ({ type, label, icon: Icon, currentUrl, preview, accepts }) => (
    <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
      <h3 className="text-lg font-medium text-white mb-4 flex items-center gap-2">
        <Icon className="w-5 h-5" /> {label}
      </h3>
      
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm text-gray-400 mb-2">Imagem Atual</label>
          {(preview || currentUrl) ? (
            <div className="relative inline-block">
              <img 
                src={preview || currentUrl} 
                alt={label} 
                className={type === 'login_background' 
                  ? 'h-32 w-full object-cover rounded-lg border border-gray-700'
                  : type === 'favicon'
                    ? 'h-16 w-16 object-contain bg-gray-900 rounded-lg border border-gray-700'
                    : 'h-20 object-contain bg-gray-900 rounded-lg p-2 border border-gray-700'
                }
              />
              <button
                onClick={() => removeImage(type)}
                className="absolute -top-2 -right-2 p-1 bg-red-600 rounded-full hover:bg-red-500"
              >
                <Trash2 className="w-3 h-3 text-white" />
              </button>
            </div>
          ) : (
            <div className={type === 'login_background' 
              ? 'h-32 w-full bg-gray-900 rounded-lg border border-gray-700 flex items-center justify-center text-gray-500'
              : type === 'favicon'
                ? 'h-16 w-16 bg-gray-900 rounded-lg border border-gray-700 flex items-center justify-center text-gray-500'
                : 'h-20 w-48 bg-gray-900 rounded-lg border border-gray-700 flex items-center justify-center text-gray-500'
            }>
              Sem imagem
            </div>
          )}
        </div>
        
        <div>
          <label className="block text-sm text-gray-400 mb-2">Nova Imagem</label>
          <div className="space-y-3">
            <label className="flex items-center gap-2 px-4 py-2 bg-gray-700 rounded-lg hover:bg-gray-600 cursor-pointer text-gray-300 w-fit">
              <Upload className="w-4 h-4" />
              Selecionar arquivo
              <input
                type="file"
                accept={accepts || 'image/*'}
                onChange={handleFileChange(type)}
                className="hidden"
              />
            </label>
            {uploads[type] && (
              <div className="flex items-center gap-3">
                <span className="text-gray-400 text-sm">{uploads[type].name}</span>
                <button
                  onClick={() => uploadImage(type)}
                  disabled={loading}
                  className="px-4 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 text-white disabled:opacity-50 text-sm"
                >
                  {loading ? 'Enviando...' : 'Enviar'}
                </button>
              </div>
            )}
          </div>
          
          {preview && type === 'login_background' && (
            <div className="mt-4">
              <label className="block text-sm text-gray-400 mb-2">Preview</label>
              <img src={preview} alt="Preview" className="h-32 w-full object-cover rounded-lg border border-gray-700" />
            </div>
          )}
        </div>
      </div>
    </div>
  );

  const renderTab = () => {
    switch (activeTab) {
      case 'branding':
        return (
          <div className="space-y-6">
            {/* Nome do Sistema */}
            <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
              <h3 className="text-lg font-medium text-white mb-4">Nome do Sistema</h3>
              <input
                type="text"
                value={settings.system_name}
                onChange={(e) => setSettings({ ...settings, system_name: e.target.value })}
                className="w-full px-3 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white"
                placeholder="LOR CGR"
              />
            </div>

            {/* Logo Principal */}
            <ImageUploader
              type="logo"
              label="Logo do Sistema"
              icon={Image}
              currentUrl={settings.logo_url}
              preview={previews.logo}
            />

            {/* Background do Login */}
            <ImageUploader
              type="login_background"
              label="Fundo da Tela de Login"
              icon={Wallpaper}
              currentUrl={settings.login_background_url}
              preview={previews.login_background}
            />

            {/* Favicon */}
            <ImageUploader
              type="favicon"
              label="Favicon (icone do navegador)"
              icon={Monitor}
              currentUrl={settings.favicon_url}
              preview={previews.favicon}
              accepts="image/x-icon,image/png,image/svg+xml"
            />

            <div className="flex justify-end">
              <button
                onClick={saveSettings}
                disabled={loading}
                className="flex items-center gap-2 px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 text-white disabled:opacity-50"
              >
                <Save className="w-4 h-4" />
                {loading ? 'Salvando...' : 'Salvar Configurações'}
              </button>
            </div>
          </div>
        );

      case 'apis':
        return (
          <div className="space-y-6">
            <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
              <h3 className="text-lg font-medium text-white mb-4">LibreNMS</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <label className="flex items-center gap-2">
                  <input type="checkbox" checked={settings.librenms_enabled} onChange={(e) => setSettings({ ...settings, librenms_enabled: e.target.checked })} className="w-4 h-4" />
                  <span className="text-gray-300">Habilitar</span>
                </label>
                <div></div>
                <div>
                  <label className="block text-sm text-gray-400 mb-1">URL</label>
                  <input type="text" value={settings.librenms_url} onChange={(e) => setSettings({ ...settings, librenms_url: e.target.value })} className="w-full px-3 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white" />
                </div>
                <div>
                  <label className="block text-sm text-gray-400 mb-1">API Token</label>
                  <input type="password" value={settings.librenms_api_token} onChange={(e) => setSettings({ ...settings, librenms_api_token: e.target.value })} className="w-full px-3 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white" />
                </div>
              </div>
            </div>

            <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
              <h3 className="text-lg font-medium text-white mb-4">phpIPAM</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <label className="flex items-center gap-2">
                  <input type="checkbox" checked={settings.phpipam_enabled} onChange={(e) => setSettings({ ...settings, phpipam_enabled: e.target.checked })} className="w-4 h-4" />
                  <span className="text-gray-300">Habilitar</span>
                </label>
                <div></div>
                <div>
                  <label className="block text-sm text-gray-400 mb-1">URL</label>
                  <input type="text" value={settings.phpipam_url} onChange={(e) => setSettings({ ...settings, phpipam_url: e.target.value })} className="w-full px-3 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white" />
                </div>
                <div>
                  <label className="block text-sm text-gray-400 mb-1">App Key</label>
                  <input type="password" value={settings.phpipam_app_key} onChange={(e) => setSettings({ ...settings, phpipam_app_key: e.target.value })} className="w-full px-3 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white" />
                </div>
              </div>
            </div>

            <div className="flex justify-end">
              <button onClick={saveSettings} disabled={loading} className="flex items-center gap-2 px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 text-white disabled:opacity-50">
                <Save className="w-4 h-4" /> Salvar
              </button>
            </div>
          </div>
        );

      case 'ai':
        return (
          <div className="space-y-6">
            <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
              <h3 className="text-lg font-medium text-white mb-4">Groq API</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <label className="flex items-center gap-2">
                  <input type="checkbox" checked={settings.ai_enabled} onChange={(e) => setSettings({ ...settings, ai_enabled: e.target.checked })} className="w-4 h-4" />
                  <span className="text-gray-300">Habilitar IA</span>
                </label>
                <div></div>
                <div>
                  <label className="block text-sm text-gray-400 mb-1">API Key</label>
                  <input type="password" value={settings.groq_api_key} onChange={(e) => setSettings({ ...settings, groq_api_key: e.target.value })} className="w-full px-3 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white" />
                </div>
                <div>
                  <label className="block text-sm text-gray-400 mb-1">Modelo</label>
                  <select value={settings.groq_model} onChange={(e) => setSettings({ ...settings, groq_model: e.target.value })} className="w-full px-3 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white">
                    <option value="llama-3.3-70b-versatile">Llama 3.3 70B</option>
                    <option value="llama-3.1-8b-instant">Llama 3.1 8B</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="flex justify-end">
              <button onClick={saveSettings} disabled={loading} className="flex items-center gap-2 px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 text-white disabled:opacity-50">
                <Save className="w-4 h-4" /> Salvar
              </button>
            </div>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div className="h-full flex flex-col">
      <div className="bg-gray-800 border-b border-gray-700 px-6 py-4">
        <h2 className="text-xl font-bold text-white">Configuracoes</h2>
      </div>

      <div className="flex-1 overflow-auto p-6">
        {message.text && (
          <div className={`mb-4 p-3 rounded-lg flex items-center gap-2 ${message.type === 'success' ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 'bg-red-500/10 text-red-400 border border-red-500/20'}`}>
            {message.type === 'success' ? <CheckCircle className="w-5 h-5" /> : <XCircle className="w-5 h-5" />}
            {message.text}
          </div>
        )}

        <div className="flex gap-2 mb-6">
          {tabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition ${activeTab === tab.id ? 'bg-blue-600 text-white' : 'bg-gray-700 text-gray-300 hover:bg-gray-600'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>

        {renderTab()}
      </div>
    </div>
  );
};

export default Settings;
